I actually started with adding just that, but wanted to make it complete and didn't want to change the structure.
I'll clean up the general case and de-complicate it, then if you still prefer the rgb16_pixel struture route, I'll finish the following.

Here is what I started with (I also placed the rgb16 bool):

`dlib/pixel.h`
```
    struct rgb16_pixel
    {
        /*!
            WHAT THIS OBJECT REPRESENTS
                This is a simple struct that represents an RGB 16-bit colored graphical pixel.
        !*/

        rgb16_pixel (
        ) {}

        rgb16_pixel (
            uint16 red_,
            uint16 green_,
            uint16 blue_
        ) : red(red_), green(green_), blue(blue_) {}

        uint16 red;
        uint16 green;
        uint16 blue;
    };
```

```
    inline void serialize (
        const rgb16_pixel& item, 
        std::ostream& out 
    );   
    /*!
        provides serialization support for the rgb16_pixel struct
    !*/

// ----------------------------------------------------------------------------------------

    inline void deserialize (
        rgb16_pixel& item, 
        std::istream& in
    );   
    /*!
        provides deserialization support for the rgb16_pixel struct
    !*/
```

```
    template <>
    struct pixel_traits<rgb16_pixel>
    {
        constexpr static bool rgb  = true;//?
        constexpr static bool rgb_alpha  = false;
        constexpr static bool grayscale = false;
        constexpr static bool hsi = false;
        constexpr static bool lab = false;
        enum { num = 3};
        typedef uint16 basic_pixel_type;
        static basic_pixel_type min() { return 0;}
        static basic_pixel_type max() { return 65535;}
        constexpr static bool is_unsigned = true;
        constexpr static bool has_alpha = false;
        constexpr static bool rgb16 = true;
    };
```

```
    inline void serialize (
        const rgb16_pixel& item, 
        std::ostream& out 
    )   
    {
        try
        {
            serialize(item.red,out);
            serialize(item.green,out);
            serialize(item.blue,out);
        }
        catch (serialization_error& e)
        {
            throw serialization_error(e.info + "\n   while serializing object of type rgb16_pixel"); 
        }
    }

// ----------------------------------------------------------------------------------------

    inline void deserialize (
        rgb16_pixel& item, 
        std::istream& in
    )   
    {
        try
        {
            deserialize(item.red,in);
            deserialize(item.green,in);
            deserialize(item.blue,in);
        }
        catch (serialization_error& e)
        {
            throw serialization_error(e.info + "\n   while deserializing object of type rgb16_pixel"); 
        }
    }
```


`dlib/serialize_pixel_overloads.h`:
```
    template <
        typename mem_manager
        >
    void serialize (
        const array2d<rgb16_pixel,mem_manager>& item, 
        std::ostream& out 
    )   
    {
        try
        {
            // The reason the serialization is a little funny is because we are trying to
            // maintain backwards compatibility with an older serialization format used by
            // dlib while also encoding things in a way that lets the array2d and matrix
            // objects have compatible serialization formats.
            serialize(-item.nr(),out);
            serialize(-item.nc(),out);

            COMPILE_TIME_ASSERT(sizeof(rgb16_pixel) == 6);
            
            if (item.size() != 0)
                out.write((uint16*)&item[0][0], sizeof(rgb16_pixel)*item.size());
        }
        catch (serialization_error e)
        { 
            throw serialization_error(e.info + "\n   while serializing object of type array2d"); 
        }
    }

    template <
        typename mem_manager
        >
    void deserialize (
        array2d<rgb16_pixel,mem_manager>& item, 
        std::istream& in
    )   
    {
        try
        {
            COMPILE_TIME_ASSERT(sizeof(rgb16_pixel) == 6);

            long nr, nc;
            deserialize(nr,in);
            deserialize(nc,in);

            // this is the newer serialization format
            if (nr < 0 || nc < 0)
            {
                nr *= -1;
                nc *= -1;
            }
            else
            {
                std::swap(nr,nc);
            }

            item.set_size(nr,nc);

            if (item.size() != 0)
                in.read((uint16*)&item[0][0], sizeof(rgb16_pixel)*item.size());
        }
        catch (serialization_error e)
        { 
            item.clear();
            throw serialization_error(e.info + "\n   while deserializing object of type array2d"); 
        }
    }
```

